import torch
# 3D CNN for spatiotemporal gas plume detection
class PlumeDetector3D(torch.nn.Module):
    def __init__(self):
        super().__init__()
        self.backbone = resnet3d_18()
        self.head = torch.nn.Linear(512, 2)  # leaking / not leaking

    def forward(self, video_clip):  # [B, C, T, H, W]
        return self.head(self.backbone(video_clip))

